import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://api.example.com/dev"
        case .staging:
            return "https://api.example.com/staging"
        case .production:
            return "https://api.example.com/prod"
        }
    }
}

class NetworkManager {
    private let environment: Environment
    private let session = URLSession.shared
    
    init(environment: Environment) {
        self.environment = environment
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<String, Error>) -> Void) {
        let url = URL(string: "\(environment.baseURL)/auth")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: String] = [
            "username": username,
            "password": password
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: body, options: [])
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(NSError(domain: "NetworkError", code: 401, userInfo: nil)))
                return
            }
            
            if let data = data, let token = String(data: data, encoding: .utf8) {
                completion(.success(token))
            } else {
                completion(.failure(NSError(domain: "NetworkError", code: 500, userInfo: nil)))
            }
        }
        
        task.resume()
    }
    
    func fetchUserData(token: String, completion: @escaping (Result<[String: Any], Error>) -> Void) {
        let url = URL(string: "\(environment.baseURL)/user")!
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.addValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(NSError(domain: "NetworkError", code: 401, userInfo: nil)))
                return
            }
            
            if let data = data, let json = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: Any] {
                completion(.success(json))
            } else {
                completion(.failure(NSError(domain: "NetworkError", code: 500, userInfo: nil)))
            }
        }
        
        task.resume()
    }
}